import type { NextApiRequest, NextApiResponse } from 'next';
import { verifyToken } from '../../../lib/auth';
import { promises as fs } from 'fs';
import path from 'path';

export default async function handler(req: NextApiRequest, res: NextApiResponse) {
  const cookie = req.headers.cookie || '';
  const match = cookie.split(';').map(c=>c.trim()).find(c=>c.startsWith('sahipath_token='));
  if (!match) return res.status(401).json({ error: 'Not authenticated' });
  const token = match.split('=')[1];
  const payload = await verifyToken(token);
  if (!payload) return res.status(401).json({ error: 'Invalid token' });

  try {
    // eslint-disable-next-line @typescript-eslint/no-var-requires
    const BetterSqlite3 = require('better-sqlite3');
    const dbPath = path.join(process.cwd(), 'data', 'app.db');
    const db = new BetterSqlite3(dbPath);
    const row = db.prepare('SELECT profile FROM users WHERE id = ?').get(String((payload as any).id));
    db.close();
    if (!row) return res.status(404).json({ error: 'User not found' });
    return res.json({ profile: row.profile ? JSON.parse(row.profile) : null });
  } catch (e:any) {
    console.error('me lookup error', e?.message || e);
    return res.status(500).json({ error: 'User lookup failed', detail: e?.message || String(e) });
  }
}
